insert into public.questions (order_index, category, type, question_text, hint_text, exclusive_option, options, matrix_items) values
  (0, 'iphone', 'single', 'How old is your iPhone?', null, null, '[{"label": "Never Used", "factor": 1.05}, {"label": "Less than 6 months", "factor": 1.02}, {"label": "6-12 months", "factor": 1.0}, {"label": "1-2 years", "factor": 0.92}, {"label": "2-3 years", "factor": 0.85}, {"label": "More than 3 years", "factor": 0.75}]'::jsonb, null),
  (1, 'iphone', 'single', 'What is the physical condition of the screen?', 'Tap the option that best describes visible damage', null, '[{"label": "No scratches or cracks", "factor": 1.0}, {"label": "Minor hairline scratches (barely visible)", "factor": 0.97}, {"label": "Visible scratches", "factor": 0.93}, {"label": "Cracked (any crack)", "factor": 0.75}]'::jsonb, null),
  (2, 'iphone', 'single', 'What is the condition of the body/back?', null, null, '[{"label": "Like new", "factor": 1.0}, {"label": "Minor scratches/dents", "factor": 0.96}, {"label": "Deep scratches/dents", "factor": 0.9}, {"label": "Cracked back glass", "factor": 0.8}]'::jsonb, null),
  (3, 'iphone', 'single', 'What is the battery health?', 'Check Settings → Battery → Battery Health', null, '[{"label": "95-100%", "factor": 1.0}, {"label": "85-94%", "factor": 0.97}, {"label": "80-84%", "factor": 0.94}, {"label": "70-79%", "factor": 0.88}, {"label": "Below 70%", "factor": 0.78}]'::jsonb, null),
  (4, 'iphone', 'multi', 'Does your iPhone have any of these issues?', null, 'No issues (Clean condition)', '[{"label": "No issues (Clean condition)", "factor": 1.0}, {"label": "Touch/display issues", "factor": 0.85}, {"label": "Speaker not working", "factor": 0.88}, {"label": "Microphone issue", "factor": 0.88}, {"label": "Camera issue", "factor": 0.86}, {"label": "Charging issue", "factor": 0.9}, {"label": "Button malfunction", "factor": 0.92}, {"label": "Other hardware issue", "factor": 0.87}]'::jsonb, null),
  (5, 'iphone', 'single', 'Is your iPhone locked or unlocked?', null, null, '[{"label": "Unlocked (any SIM)", "factor": 1.0}, {"label": "Locked to a carrier", "factor": 0.9}, {"label": "iCloud/Activation locked", "factor": 0.0}]'::jsonb, null),
  (6, 'iphone', 'single', 'Have you done any repairs on this phone?', null, null, '[{"label": "No repairs", "factor": 1.0}, {"label": "Screen replaced (Apple/authorised)", "factor": 0.97}, {"label": "Screen replaced (third-party)", "factor": 0.9}, {"label": "Battery replaced (Apple/authorised)", "factor": 0.98}, {"label": "Battery replaced (third-party)", "factor": 0.93}, {"label": "Other repair", "factor": 0.92}]'::jsonb, null),
  (7, 'iphone', 'single', 'Does your iPhone have AppleCare+ or warranty?', null, null, '[{"label": "Yes, active AppleCare+", "factor": 1.04}, {"label": "Yes, standard warranty still valid", "factor": 1.02}, {"label": "No warranty", "factor": 1.0}]'::jsonb, null),
  (8, 'iphone', 'single', 'Do you have the original Apple charger/cable?', null, null, '[{"label": "Yes, original unused", "factor": 1.02}, {"label": "Yes, original used", "factor": 1.01}, {"label": "No / third-party", "factor": 1.0}]'::jsonb, null),
  (9, 'iphone', 'single', 'Do you have the original box?', null, null, '[{"label": "Yes", "factor": 1.03}, {"label": "No", "factor": 1.0}]'::jsonb, null),
  (10, 'iphone', 'single', 'What is the storage showing in Settings?', 'Confirm via Settings → General → About → Capacity', null, '[{"label": "Matches the storage I selected", "factor": 1.0}, {"label": "Less than expected", "factor": 0.85}]'::jsonb, null),
  (11, 'iphone', 'single', 'Will you include all original accessories?', null, null, '[{"label": "Yes, all original accessories", "factor": 1.01}, {"label": "Some accessories", "factor": 1.0}, {"label": "No accessories", "factor": 1.0}]'::jsonb, null),
  (12, 'iphone', 'matrix', 'Check each device function — working or not?', 'Try each one before answering', null, null, '[{"label": "WiFi", "yesFactor": 1.0, "noFactor": 0.85}, {"label": "Bluetooth", "yesFactor": 1.0, "noFactor": 0.9}, {"label": "Speaker", "yesFactor": 1.0, "noFactor": 0.85}, {"label": "Earpiece Speaker", "yesFactor": 1.0, "noFactor": 0.88}, {"label": "Face ID", "yesFactor": 1.0, "noFactor": 0.88}, {"label": "GPS", "yesFactor": 1.0, "noFactor": 0.92}, {"label": "Flashlight", "yesFactor": 1.0, "noFactor": 0.95}, {"label": "Wireless Charging", "yesFactor": 1.0, "noFactor": 0.93}, {"label": "Normal Charging", "yesFactor": 1.0, "noFactor": 0.8}, {"label": "Panic Error Present", "yesFactor": 0.78, "noFactor": 1.0}, {"label": "SIM Lock", "yesFactor": 0.82, "noFactor": 1.0}, {"label": "Power Button", "yesFactor": 1.0, "noFactor": 0.9}, {"label": "Volume Buttons", "yesFactor": 1.0, "noFactor": 0.93}, {"label": "Silent Switch", "yesFactor": 1.0, "noFactor": 0.95}, {"label": "Vibration", "yesFactor": 1.0, "noFactor": 0.93}]'::jsonb);
insert into public.questions (order_index, category, type, question_text, hint_text, exclusive_option, options, matrix_items) values
  (0, 'macbook', 'single', 'How old is your MacBook?', null, null, '[{"label": "Never Used", "factor": 1.05}, {"label": "Under 6 months", "factor": 1.02}, {"label": "6–12 months", "factor": 1.0}, {"label": "1–2 years", "factor": 0.93}, {"label": "2–3 years", "factor": 0.86}, {"label": "3–5 years", "factor": 0.75}, {"label": "More than 5 years", "factor": 0.62}]'::jsonb, null),
  (1, 'macbook', 'single', 'What is the condition of the screen?', 'Open the lid fully and inspect at different angles', null, '[{"label": "No dead pixels, no scratches", "factor": 1.0}, {"label": "Minor hairline scratches (barely visible)", "factor": 0.97}, {"label": "Visible scratches", "factor": 0.92}, {"label": "Dead pixel(s) present", "factor": 0.8}, {"label": "Cracked or shattered screen", "factor": 0.6}]'::jsonb, null),
  (2, 'macbook', 'single', 'What is the condition of the body / chassis?', null, null, '[{"label": "Like new, no dents or scratches", "factor": 1.0}, {"label": "Minor scratches (normal use)", "factor": 0.97}, {"label": "Visible dents or deep scratches", "factor": 0.9}, {"label": "Significant damage (bent, cracked)", "factor": 0.75}]'::jsonb, null),
  (3, 'macbook', 'single', 'What is the approximate battery cycle count?', 'Check via Apple menu → About This Mac → System Report → Power', null, '[{"label": "Under 100 cycles", "factor": 1.02}, {"label": "100–300 cycles", "factor": 1.0}, {"label": "300–500 cycles", "factor": 0.95}, {"label": "500–800 cycles", "factor": 0.88}, {"label": "Over 800 cycles", "factor": 0.78}, {"label": "Battery swollen or replaced (3rd party)", "factor": 0.7}]'::jsonb, null),
  (4, 'macbook', 'single', 'Is the keyboard fully functional?', 'Test every key including function keys and Touch Bar if present', null, '[{"label": "All keys working perfectly", "factor": 1.0}, {"label": "1–2 sticky or unresponsive keys", "factor": 0.9}, {"label": "Multiple keys not working", "factor": 0.78}, {"label": "Keyboard replaced (Apple authorised)", "factor": 0.97}, {"label": "Keyboard replaced (3rd party)", "factor": 0.88}]'::jsonb, null),
  (5, 'macbook', 'single', 'What is the condition of the trackpad?', null, null, '[{"label": "Works perfectly, Force Touch responsive", "factor": 1.0}, {"label": "Minor issues (click feedback slightly off)", "factor": 0.95}, {"label": "Trackpad not clicking / unresponsive", "factor": 0.8}, {"label": "Cracked trackpad surface", "factor": 0.75}]'::jsonb, null),
  (6, 'macbook', 'single', 'Are all ports working correctly?', 'Test Thunderbolt/USB-C ports and MagSafe if applicable', null, '[{"label": "All ports working", "factor": 1.0}, {"label": "One port not working", "factor": 0.93}, {"label": "Two or more ports not working", "factor": 0.82}, {"label": "Charging port not working", "factor": 0.75}]'::jsonb, null),
  (7, 'macbook', 'single', 'Is iCloud / Activation Lock cleared?', 'Sign out of iCloud in System Settings before selling', null, '[{"label": "Yes, signed out of iCloud", "factor": 1.0}, {"label": "Not yet but I will before pickup", "factor": 0.98}, {"label": "Device has Activation Lock (unknown password)", "factor": 0.0}]'::jsonb, null),
  (8, 'macbook', 'single', 'Have any repairs been done on this MacBook?', null, null, '[{"label": "No repairs", "factor": 1.0}, {"label": "Screen replaced (Apple/authorised)", "factor": 0.96}, {"label": "Screen replaced (3rd party)", "factor": 0.88}, {"label": "Battery replaced (Apple/authorised)", "factor": 0.97}, {"label": "Battery replaced (3rd party)", "factor": 0.88}, {"label": "Logic board repaired", "factor": 0.82}, {"label": "Other repair", "factor": 0.9}]'::jsonb, null),
  (9, 'macbook', 'single', 'Do you have the original Apple charger?', null, null, '[{"label": "Yes, original charger included", "factor": 1.02}, {"label": "Yes but it''s damaged/frayed", "factor": 0.99}, {"label": "No charger / 3rd party only", "factor": 1.0}]'::jsonb, null),
  (10, 'macbook', 'single', 'Do you have the original box?', null, null, '[{"label": "Yes", "factor": 1.02}, {"label": "No", "factor": 1.0}]'::jsonb, null),
  (11, 'macbook', 'multi', 'Does your MacBook have any of these issues?', null, 'None of the above', '[{"label": "None of the above", "factor": 1.0}, {"label": "Fan very loud / overheating", "factor": 0.88}, {"label": "Speaker crackling or not working", "factor": 0.88}, {"label": "Microphone not working", "factor": 0.9}, {"label": "Webcam not working", "factor": 0.9}, {"label": "Wi-Fi dropping or not connecting", "factor": 0.85}, {"label": "Bluetooth not working", "factor": 0.92}, {"label": "Display flickering or backlight issues", "factor": 0.82}, {"label": "Kernel panics / frequent crashes", "factor": 0.78}]'::jsonb, null),
  (12, 'macbook', 'single', 'Will the MacBook power on and boot normally?', null, null, '[{"label": "Yes, boots normally", "factor": 1.0}, {"label": "Boots but has issues (slow, freezing)", "factor": 0.85}, {"label": "Does not power on", "factor": 0.5}]'::jsonb, null);
insert into public.reviews (name, city, rating, review_text, is_published) values
  ('Rahul Mehta', 'Mumbai', 5, 'Sold my iPhone 13 Pro in under an hour. The executive arrived on time and paid instantly via UPI. Smooth experience.', true),
  ('Priya Nair', 'Thane', 5, 'Best price I could find anywhere. Doorstep pickup made it so convenient — no haggling at the door.', true),
  ('Aditya Sharma', 'Navi Mumbai', 4, 'Quick quote and fair value for my MacBook Air. Slight delay in the pickup call but overall great.', true),
  ('Sneha Kulkarni', 'Mumbai', 5, 'The condition quiz was detailed and the final price matched the online quote exactly. Very trustworthy.', true),
  ('Imran Shaikh', 'Thane', 5, 'Got paid on the spot in cash. IMEI verified everything transparently. Would sell again.', true),
  ('Neha Desai', 'Navi Mumbai', 5, 'Sold two iPhones together and got a combined deal. Super easy and fully insured pickup.', true);
